package com.mengwei.localgrowth.execution;
import static com.mengwei.localgrowth.execution.BlockedSnapshot.storefrontRequiredSnapshot;
import com.fasterxml.jackson.databind.*;import com.mengwei.localgrowth.audit.AuditService;import com.mengwei.localgrowth.fact.VerifiedFactResolver;import com.mengwei.localgrowth.identity.AuthService.Identity;import com.mengwei.localgrowth.model.*;import com.mengwei.localgrowth.shared.ApiExceptionHandler.ApiException;import java.time.OffsetDateTime;import java.util.*;import org.springframework.http.HttpStatus;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;
@Service public class RealContentService{private final JdbcTemplate jdbc;private final OpenAiCompatibleProvider provider;private final VerifiedFactResolver resolver;private final AuditService audit;private final ObjectMapper mapper;private static final Set<String> CHANNELS=Set.of("WEBSITE","XIAOHONGSHU","DIANPING","DOUYIN","WECHAT","ZHIHU");public RealContentService(JdbcTemplate j,OpenAiCompatibleProvider p,VerifiedFactResolver r,AuditService a,ObjectMapper m){jdbc=j;provider=p;resolver=r;audit=a;mapper=m;}public Map<String,Object> status(){return Map.of("provider",provider.name(),"configured",provider.configured());}public Map<String,Object> testConnection(){var a=provider.invoke("仅返回{\"ok\":true}","","","中国");return Map.of("provider",provider.name(),"model",a.model(),"success",true);}
 public Map<String,Object> preview(Identity i,UUID task,UUID store){var t=task(i,task);var r=resolver.resolve(i,(UUID)t.get("merchant_id"),store,OffsetDateTime.now());return Map.of("storefrontId",r.store(),"verifiedFacts",r.facts(),"prohibitedClaims",r.prohibited(),"unavailableFactCount",unavailable(i,(UUID)t.get("merchant_id")));}
 public Map<String,Object> generate(Identity i,UUID taskId,String channel,UUID store){if(!CHANNELS.contains(channel))throw bad("CHANNEL_INVALID","不支持的平台");var t=task(i,taskId);UUID merchant=(UUID)t.get("merchant_id");UUID rid=UUID.randomUUID();String pv="fact-center-real-v1";VerifiedFactResolver.Resolved r;try{r=resolver.resolve(i,merchant,store,OffsetDateTime.now());}catch(ApiException e){if(!"STOREFRONT_REQUIRED".equals(e.code()))throw e;String snapshot=storefrontRequiredSnapshot(merchant);List<String> missing=List.of("STOREFRONT_REQUIRED");String reason="存在多个门店，请选择门店后重试";save(i,rid,t,null,null,snapshot,missing,List.of(),0L,"BLOCKED",reason,pv,null);audit.log(i.tenantId(),i.userId(),"FACT_SNAPSHOT_BLOCKED","AiGeneration",rid,"merchantId="+merchant+", storefrontId=null, reason=STOREFRONT_REQUIRED");Map<String,Object> response=new LinkedHashMap<>();response.put("generationBlocked",true);response.put("missingFacts",missing);response.put("executionStatus","BLOCKED");response.put("reason",reason);response.put("aiGenerationId",rid);response.put("factSnapshot",snapshot);return response;}String snapshot=resolver.snapshot(r);List<String> missing=required(String.valueOf(t.get("task_type")),r.facts());if(!missing.isEmpty()){save(i,rid,t,null,r.store(),snapshot,missing,List.of(),0L,"BLOCKED","缺少已核验事实："+String.join(",",missing),pv,null);audit.log(i.tenantId(),i.userId(),"FACT_SNAPSHOT_BLOCKED","AiGeneration",rid,"merchantId="+merchant+", storefrontId="+r.store()+", facts="+r.facts().size());return Map.of("generationBlocked",true,"missingFacts",missing,"reason","资料不足，未调用模型","factSnapshot",snapshot);}
  String facts=r.facts().stream().map(x->x.get("fact_type")+"："+x.get("normalized_text")+"（factVersionId="+x.get("version_id")+"）").reduce("",(a,b)->a+"\n"+b);String prohibited=r.prohibited().stream().map(x->String.valueOf(x.get("normalized_text"))).reduce("",(a,b)->a+"；"+b);try{var answer=provider.invoke("只返回JSON：title,content,usedFacts,missingFacts,riskFlags。商家官方内容，不得冒充消费者UGC。只能使用以下事实，usedFacts必须填写factVersionId数组；禁止宣传事项："+prohibited+"。\n事实："+facts+"\n任务："+t.get("description")+"\n平台："+channel,String.valueOf(t.get("title")),facts,"");Map<String,Object> out=parse(answer.text());String content=String.valueOf(out.getOrDefault("content",""));List<String> risks=risks(content);ProhibitedClaimGuard.Result guard=new ProhibitedClaimGuard(mapper).check(String.valueOf(out.getOrDefault("title","")),content,r.prohibited(),risks);risks=new ArrayList<>(guard.riskFlags());List<String> used=strings(out.get("usedFacts"));Set<String> ids=new HashSet<>();r.facts().forEach(x->ids.add(String.valueOf(x.get("version_id"))));if(used.stream().anyMatch(x->!ids.contains(x)))risks.add("FACT_NOT_VERIFIED");if(!prohibited.isBlank()&&content.contains(prohibited))risks.add("PROHIBITED_CLAIM_HIT");if(content.isBlank()||!out.containsKey("title")){save(i,rid,t,null,r.store(),snapshot,List.of(),risks,answer.tokenUsage(),"FAILED","模型结构化响应无内容",pv,answer);throw bad("MODEL_RESPONSE_INVALID","模型返回不完整");}UUID asset=asset(i,t,r.store(),channel,content,snapshot,risks,pv);save(i,rid,t,asset,r.store(),snapshot,strings(out.get("missingFacts")),risks,answer.tokenUsage(),"SUCCEEDED",null,pv,answer);Map<String,Object> structured=new LinkedHashMap<>();structured.put("matchedClaims",guard.matchedClaims());structured.put("highestSeverity",guard.highestSeverity());structured.put("reviewSubmissionBlocked",guard.reviewSubmissionBlocked());jdbc.update("update ai_generation_records set structured_output=?::jsonb where id=? and tenant_id=?",json(structured),rid,i.tenantId());audit.log(i.tenantId(),i.userId(),"FACT_SNAPSHOT_READ","AiGeneration",rid,"merchantId="+merchant+", storefrontId="+r.store()+", facts="+r.facts().size());Map<String,Object> response=new LinkedHashMap<>();response.put("generationBlocked",false);response.put("provider",provider.name());response.put("model",answer.model());response.put("promptVersion",pv);response.put("generatedContent",content);response.put("title",out.get("title"));response.put("usedFacts",used);response.put("missingFacts",strings(out.get("missingFacts")));response.put("riskFlags",risks);response.put("factSnapshot",snapshot);response.put("aiGenerationId",rid);response.put("contentAssetId",asset);return response;}catch(ApiException e){throw e;}catch(Exception e){save(i,rid,t,null,r.store(),snapshot,List.of(),List.of(),0L,"FAILED",e.getMessage(),pv,null);throw new ApiException(HttpStatus.BAD_GATEWAY,"MODEL_CALL_FAILED","真实模型调用失败，调用记录已保存");}}
 private List<String> required(String type,List<Map<String,Object>> f){Set<String>s=new HashSet<>();f.forEach(x->s.add(String.valueOf(x.get("fact_type"))));List<String> need=switch(type){case "LOCATION_CONTENT"->List.of("BRAND_NAME","STORE_NAME","ADDRESS_OR_SERVICE_AREA");case "PRICE_CONTENT"->List.of("BRAND_NAME","SERVICE_ITEM","PRICE_RANGE_OR_PACKAGE");case "LOCAL_LISTING"->List.of("STORE_NAME","ADDRESS","PHONE","BUSINESS_HOURS","SERVICE_ITEM");case "CASE_STUDY"->List.of("BRAND_NAME","CASE_STUDY");default->List.of("BRAND_NAME","SERVICE_ITEM");};return need.stream().filter(x->x.equals("ADDRESS_OR_SERVICE_AREA")?!(s.contains("ADDRESS")||s.contains("SERVICE_AREA")):x.equals("PRICE_RANGE_OR_PACKAGE")?!(s.contains("PRICE_RANGE")||s.contains("PACKAGE")):!s.contains(x)).toList();}
 private UUID asset(Identity i,Map<String,Object>t,UUID store,String channel,String content,String snap,List<String>risks,String pv){UUID id=UUID.randomUUID();OffsetDateTime n=OffsetDateTime.now();jdbc.update("insert into content_assets (id,tenant_id,merchant_id,source_task_id,storefront_id,channel,title,content,fact_snapshot,prompt_version,generation_version,risk_flags,review_status,created_at,updated_at,created_by,updated_by,version) values (?,?,?,?,?,?,?,?,?::jsonb,?,?,?::jsonb,?,?,?,?,?,?)",id,i.tenantId(),t.get("merchant_id"),t.get("id"),store,channel,"真实模型草稿｜"+t.get("title"),content,snap,pv,"real-model-v2",json(risks),"DRAFT",n,n,i.userId(),i.userId(),0L);return id;}
 private void save(Identity i,UUID id,Map<String,Object>t,UUID asset,UUID store,String snap,List<String>miss,List<String>risks,Long token,String status,String err,String pv,ModelProviderPort.ModelAnswer a){String content=asset==null?"":jdbc.queryForObject("select content from content_assets where id=?",String.class,asset);jdbc.update("insert into ai_generation_records (id,tenant_id,merchant_id,source_task_id,content_asset_id,storefront_id,provider,model,prompt_version,input_facts,generated_content,missing_facts,risk_flags,token_usage,created_at,created_by,execution_status,error_message,http_status) values (?,?,?,?,?,?,?,?,?,?::jsonb,?,?::jsonb,?::jsonb,?,?,?,?,?,?)",id,i.tenantId(),t.get("merchant_id"),t.get("id"),asset,store,provider.name(),provider.configuredModel(),pv,snap,content,json(miss),json(risks),token,OffsetDateTime.now(),i.userId(),status,err,a==null?null:a.httpStatus());}
 private Map<String,Object>task(Identity i,UUID id){var x=jdbc.queryForList("select * from optimization_tasks where id=? and tenant_id=?",id,i.tenantId());if(x.isEmpty())throw bad("NOT_FOUND","任务不存在");return x.getFirst();}private int unavailable(Identity i,UUID m){return jdbc.queryForObject("select count(*) from merchant_facts f join merchant_fact_versions v on v.id=f.current_version_id where f.tenant_id=? and f.merchant_id=? and not f.deleted and v.status<>'VERIFIED'",Integer.class,i.tenantId(),m);}private List<String>risks(String x){List<String>r=new ArrayList<>();if(x.matches("(?s).*(治疗|治愈|疗效).*"))r.add("MEDICAL_PROMISE");if(x.matches("(?s).*(最好|第一|百分之百|保证).*"))r.add("ABSOLUTE_CLAIM");return r;}@SuppressWarnings("unchecked")private Map<String,Object>parse(String s){try{String x=s.trim().replaceFirst("^```json\\s*","").replaceFirst("\\s*```$","");return mapper.readValue(x,Map.class);}catch(Exception e){throw bad("MODEL_RESPONSE_INVALID","模型返回非法JSON");}}private List<String>strings(Object o){return o instanceof Collection<?>c?c.stream().map(String::valueOf).toList():List.of();}private String json(Object o){try{return mapper.writeValueAsString(o);}catch(Exception e){throw new IllegalStateException(e);}}private ApiException bad(String c,String m){return new ApiException(HttpStatus.BAD_REQUEST,c,m);}}
